#!/usr/bin/env bash
# compliance-and-privacy-pipeline.sh — Compliance and Privacy Pipeline SOP walkthrough for AI自适应学习.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI自适应学习"
WORKFLOW="Compliance and Privacy Pipeline"

usage() {
  cat <<EOF
compliance-and-privacy-pipeline.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./compliance-and-privacy-pipeline.sh             # interactive
  ./compliance-and-privacy-pipeline.sh --dry-run
  ./compliance-and-privacy-pipeline.sh --json
  ./compliance-and-privacy-pipeline.sh --explain
  ./compliance-and-privacy-pipeline.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Compliance and Privacy Pipeline" 工作流。

入门 SOP 共 1 步, 失败模式自检 0 项。

相关心智模型:
  • 追踪-适应闭环 (Trace-then-Adapt Loop): 自适应学习的核心运作模式是「持续估计学生的潜在知识状态 → 基于估计选择最优下一步教学动作」的概率闭环, 而非简单的分数累加-推荐
  • 粒度决定效果 (Granularity Determines Effectiveness): 自适应的粒度越细 (从课程级→单元级→步骤级→子步骤级), 效果越接近人类一对一辅导 — VanLehn (2011) meta-review 证实步骤级 ITS 效果量约 d=0.76 (业内估),

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "Conduct data inventory: catalog all student PII collected (name, email, interaction logs, assessment responses, device info), where it is stored, how it flows between services, and who has access. Create a data flow diagram. 2. Identify applicable regulations by market: US K-12 (FERPA + COPPA for <13); US higher ed (FERPA); EU (GDPR); China (个人信息保护法 + 双减); global (WCAG 2.1 AA for accessibility). 3. For FERPA: ensure the platform qualifies as a \"school official\" under the institution's annual notification, or obtain written consent. Implement \"legitimate educational interest\" access controls — only users with a need-to-know can access student records. 4. For COPPA (<13 users): implement verifiable parental consent before collecting data. The 2024 COPPA amendments require opt-in (not opt-out) for AI training and third-party sharing. 5. For GDPR: implement data subject rights (access, rectification, erasure, portability). Establish lawful basis (typically legitimate interest or contract for EdTech). Appoint DPO if processing data of EU students at scale. 6. Draft and sign Data Processing Agreements (DPAs) with all institutional customers: specify data ownership (institution owns), usage limitations (no advertising, no selling), retention/deletion schedule, breach notification timeline (72 hours for GDPR, varies by US state). 7. Implement technical safeguards: AES-256 encryption at rest, TLS 1.3 in transit, RBAC, audit logging, data minimization. For AI/LLM components: ensure student PII does not enter model training data (use RAG with ephemeral context, not fine-tuning on student data). 8. Conduct annual compliance audit; maintain SOC 2 Type II or equivalent certification."
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "compliance-and-privacy-pipeline-walkthrough"
fi
